        $commits = @(
            @{ type = "feat"; subject = "add new endpoint"; breaking = $false }
        )

        $result = Invoke-SemanticVersionBump -VersionFilePath $script:packagePath -Commits $commits

        $result.NewVersion | Should -Be "1.1.0"
